class SessionDelegate: NSObject, URLSessionDelegate {
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust {
            if let serverTrust = challenge.protectionSpace.serverTrust {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
                return
            }
        }
        completionHandler(.performDefaultHandling, nil)
    }
}

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case delete = "DELETE"
    case patch = "PATCH"
    case head = "HEAD"
    case options = "OPTIONS"
}

struct HTTPResponse {
    let statusCode: Int
    let headers: [String: String]
    let data: Data
    
    var isSuccess: Bool {
        return (200...299).contains(statusCode)
    }
    
    var bodyString: String? {
        return String(data: data, encoding: .utf8)
    }
}

enum HTTPError: Error {
    case invalidURL
    case invalidResponse
    case networkError(Error)
    case encodingError(Error)
    case decodingError(Error)
    case httpError(statusCode: Int, data: Data)
    
    var localizedDescription: String {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .invalidResponse:
            return "Invalid response from server"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .encodingError(let error):
            return "Encoding error: \(error.localizedDescription)"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .httpError(let statusCode, _):
            return "HTTP error with status code: \(statusCode)"
        }
    }
}

class DeviceManager {
    static let shared = DeviceManager()
    
    private init() {}
    
    func discoverLocalDevices(completion: @escaping ([IoTDevice]) -> Void) {
        var devices: [IoTDevice] = []
        let group = DispatchGroup()
        
        for i in 1...254 {
            group.enter()
            let ip = "192.168.1.\(i)"
            let url = "http://\(ip):80/api/info"
            
            HTTPClient.shared.get(url: url) { result in
                defer { group.leave() }
                
                switch result {
                case .success(let response):
                    if response.isSuccess {
                        let device = IoTDevice(ipAddress: ip, name: "Device-\(i)", status: .online)
                        devices.append(device)
                    }
                case .failure:
                    break
                }
            }
        }
        
        group.notify(queue: .main) {
            completion(devices)
        }
    }
    
    func controlDevice(ipAddress: String, command: DeviceCommand, completion: @escaping (Result<String, HTTPError>) -> Void) {
        let url = "http://\(ipAddress):80/api/control"
        
        HTTPClient.shared.uploadJSON(url: url, method: .post, object: command) { result in
            switch result {
            case .success(let response):
                if response.isSuccess {
                    completion(.success(response.bodyString ?? "Success"))
                } else {
                    completion(.failure(.httpError(statusCode: response.statusCode, data: response.data)))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getDeviceStatus(ipAddress: String, completion: @escaping (Result<DeviceStatus, HTTPError>) -> Void) {
        let url = "http://\(ipAddress):80/api/status"
        
        HTTPClient.shared.downloadJSON(url: url, type: DeviceStatus.self) { result in
            completion(result)
        }
    }
}

class CloudAPIManager {
    static let shared = CloudAPIManager()
    private let baseURL = "https://api.example.com"
    
    private init() {}
    
    func login(username: String, password: String, completion: @escaping (Result<AuthResponse, HTTPError>) -> Void) {
        let url = "\(baseURL)/auth/login"
        let credentials = LoginCredentials(username: username, password: password)
        
        HTTPClient.shared.uploadJSON(url: url, method: .post, object: credentials) { result in
            switch result {
            case .success(let response):
                if response.isSuccess {
                    do {
                        let authResponse = try JSONDecoder().decode(AuthResponse.self, from: response.data)
                        completion(.success(authResponse))
                    } catch {
                        completion(.failure(.decodingError(error)))
                    }
                } else {
                    completion(.failure(.httpError(statusCode: response.statusCode, data: response.data)))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getUserDevices(token: String, completion: @escaping (Result<[CloudDevice], HTTPError>) -> Void) {
        let url = "\(baseURL)/devices"
        let headers = ["Authorization": "Bearer \(token)"]
        
        HTTPClient.shared.downloadJSON(url: url, type: DevicesResponse.self) { result in
            switch result {
            case .success(let devicesResponse):
                completion(.success(devicesResponse.devices))
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func updateDeviceSettings(deviceId: String, token: String, settings: DeviceSettings, completion: @escaping (Result<HTTPResponse, HTTPError>) -> Void) {
        let url = "\(baseURL)/devices/\(deviceId)/settings"
        let headers = ["Authorization": "Bearer \(token)"]
        
        HTTPClient.shared.uploadJSON(url: url, method: .put, object: settings) { result in
            completion(result)
        }
    }
}

